import React, { useState } from 'react';
import { Form, Button, Card, Alert, Container } from 'react-bootstrap';
import { useAuth } from '../context/AuthContext';

function Login() {
  const [email, setEmail] = useState('admin@example.com');
  const [password, setPassword] = useState('password123');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const result = await login(email, password);
    if (!result.success) setError(result.message);
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #1a1a1a 0%, #2d2d2d 50%, #8B0000 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    }}>
      <Container>
        <div className="text-center mb-4">
          <div style={{
            width: 100,
            height: 100,
            background: 'white',
            borderRadius: 20,
            display: 'inline-flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '3rem',
            boxShadow: '0 10px 40px rgba(0,0,0,0.5)',
            marginBottom: 20
          }}>
            🚗
          </div>
          <h1 style={{ color: 'white', fontWeight: 700, letterSpacing: 2 }}>AUTOPARTS</h1>
          <p style={{ color: 'rgba(255,255,255,0.7)' }}>Система управления продажами</p>
        </div>

        <Card style={{
          maxWidth: 420,
          margin: '0 auto',
          borderRadius: 16,
          border: 'none',
          boxShadow: '0 20px 60px rgba(0,0,0,0.4)',
          overflow: 'hidden'
        }}>
          <div style={{
            background: '#8B0000',
            padding: '16px 20px',
            color: 'white',
            fontWeight: 600,
            fontSize: '1.1rem'
          }}>
            🔐 Вход в систему
          </div>
          <Card.Body style={{ padding: 32 }}>
            {error && <Alert variant="danger">{error}</Alert>}

            <Form onSubmit={handleSubmit}>
              <Form.Group className="mb-3">
                <Form.Label style={{ fontWeight: 500, color: '#333' }}>Email</Form.Label>
                <Form.Control
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  style={{
                    borderRadius: 8,
                    padding: 10,
                    border: '2px solid #e0e0e0'
                  }}
                />
              </Form.Group>

              <Form.Group className="mb-4">
                <Form.Label style={{ fontWeight: 500, color: '#333' }}>Пароль</Form.Label>
                <Form.Control
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                  style={{
                    borderRadius: 8,
                    padding: 10,
                    border: '2px solid #e0e0e0'
                  }}
                />
              </Form.Group>

              <Button
                type="submit"
                style={{
                  width: '100%',
                  padding: 12,
                  borderRadius: 8,
                  backgroundColor: '#8B0000',
                  border: 'none',
                  fontWeight: 600,
                  fontSize: '1.1rem',
                  transition: 'all 0.3s'
                }}
                disabled={loading}
                onMouseOver={(e) => e.target.style.backgroundColor = '#660000'}
                onMouseOut={(e) => e.target.style.backgroundColor = '#8B0000'}
              >
                {loading ? '⏳ Вход...' : '🚪 Войти'}
              </Button>
            </Form>

            <div className="text-center mt-3" style={{ color: '#999', fontSize: '0.85rem' }}>
              Тестовый доступ: admin@example.com / password123
            </div>
          </Card.Body>
        </Card>
      </Container>
    </div>
  );
}

export default Login;
